document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("form-mensagem"),r=document.getElementById("resultado");e&&r?e.addEventListener("submit",async t=>{t.preventDefault();const n=new FormData(e),o=Object.fromEntries(n.entries());try{const t=await fetch("../logica/salvar-mensagem.php",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:new URLSearchParams(o).toString()});if(!t.ok)throw new Error(`HTTP error! status: ${t.status}`);const n=await t.json();n.success?(r.innerHTML=`<div class="alert alert-success">${n.message}</div>`,e.reset()):r.innerHTML=`<div class="alert alert-danger">${n.message}</div>`}catch(s){const e=s instanceof Error?s.message:"Erro desconhecido";r.innerHTML=`<div class="alert alert-danger">Erro ao enviar: ${e}</div>`,console.error("Erro na requisição:",s)}}):console.error("Elementos do formulário não encontrados.")});
